     4→async function addIngredient(page: any, ingredientName: string, quantity?: string, unit?: string) {
     5→  // Click ingredient combobox
     6→  const ingredientCombobox = page.getByTestId("ingredient-combobox").first();
     7→  await ingredientCombobox.click();
     8→
     9→  // Type the ingredient name in the search input
    10→  const searchInput = page.getByPlaceholder("Search or type new...").first();
    11→  await searchInput.fill(ingredientName);
    12→
    13→  // Wait for the dropdown to update
    14→  await page.waitForTimeout(300);
    15→
    16→  // Use keyboard navigation to select
    17→  await searchInput.press("ArrowDown");
    18→  await searchInput.press("Enter");
    19→
    20→  // Wait for the popover to close
    21→  await page.waitForTimeout(200);
    22→
    23→  // Fill in quantity if provided
    24→  if (quantity) {
    25→    await page.getByPlaceholder("Qty").first().fill(quantity);
    26→  }
    27→
    28→  // Select unit using the unit combobox if provided
    29→  if (unit) {
    30→    const unitCombobox = page.getByTestId("unit-combobox").first();
