    await expect(page).toHaveURL(/\?.*search=Search\+URL/);
  });

  test("Clear restores all", async ({ page }) => {
    const timestamp = Date.now();
    const recipe1 = `Clear Test First ${timestamp}`;
    const recipe2 = `Clear Test Second ${timestamp}`;

