    11→export async function loader({ request }: Route.LoaderArgs) {
    12→  const url = new URL(request.url);
    13→  const search = url.searchParams.get("search") || undefined;
    14→  const tagsParam = url.searchParams.get("tags");
    15→  const tags = tagsParam ? tagsParam.split(",").filter(Boolean) : undefined;
    16→  const view = url.searchParams.get("view") || "cards";
    17→
    18→  const [recipes, allTags] = await Promise.all([
    19→    listRecipes({ search, tags }),
    20→    getAllTags(),
    21→  ]);
    22→
    23→  return { recipes, allTags, filters: { search, tags }, view };
    24→}
    25→
    26→export async function action({ request }: Route.ActionArgs) {
    27→  const formData = await request.formData();
    28→  const intent = formData.get("intent");
    29→
    30→  if (intent === "cleanup-test-recipes") {
    31→    const pattern = formData.get("pattern") as string;
    32→    if (pattern && pattern.length >= 3) {
    33→      const deletedCount = await deleteRecipesByPattern(pattern);
    34→      return { success: true, deletedCount };
    35→    }
    36→    return data({ error: "Pattern must be at least 3 characters" }, { status: 400 });
    37→  }
    38→
    39→  return data({ error: "Unknown action" }, { status: 400 });
    40→}
