     1→import { query, queryOne } from "~/db/connection";
     2→import type { CreateRecipeInput, RecipeFilter } from "../schemas/recipe";
     3→
     4→export interface Recipe {
     5→  id: string;
     6→  name: string;
     7→  instructions: string;
     8→  prepTimeMinutes: number | null;
     9→  cookTimeMinutes: number | null;
    10→  servings: number | null;
    11→  sourceUrl: string | null;
    12→  notes: string | null;
    13→  createdAt: Date;
    14→  updatedAt: Date;
    15→}
    16→
    17→export interface RecipeWithDetails extends Recipe {
    18→  ingredients: {
    19→    id: string;
    20→    name: string;
    21→    quantity: number | null;
    22→    unit: string | null;
    23→    notes: string | null;
    24→    sortOrder: number;
    25→  }[];
    26→  tags: { id: string; name: string }[];
    27→}
    28→
    29→export async function createRecipe(input: CreateRecipeInput): Promise<Recipe> {
    30→  const recipe = await queryOne<Recipe>(
    31→    `INSERT INTO recipes (name, instructions, prep_time_minutes, cook_time_minutes, servings, source_url, notes)
    32→     VALUES ($1, $2, $3, $4, $5, $6, $7)
    33→     RETURNING id, name, instructions, prep_time_minutes as "prepTimeMinutes",
    34→               cook_time_minutes as "cookTimeMinutes", servings, source_url as "sourceUrl",
    35→               notes, created_at as "createdAt", updated_at as "updatedAt"`,
    36→    [
    37→      input.name,
    38→      input.instructions,
    39→      input.prepTimeMinutes,
    40→      input.cookTimeMinutes,
    41→      input.servings,
    42→      input.sourceUrl || null,
    43→      input.notes,
    44→    ]
    45→  );
    46→
