   132→export async function listRecipes(filter?: RecipeFilter): Promise<Recipe[]> {
   133→  let sql = `
   134→    SELECT DISTINCT r.id, r.name, r.instructions, r.prep_time_minutes as "prepTimeMinutes",
   135→           r.cook_time_minutes as "cookTimeMinutes", r.servings, r.source_url as "sourceUrl",
   136→           r.notes, r.created_at as "createdAt", r.updated_at as "updatedAt"
   137→    FROM recipes r
   138→  `;
   139→
   140→  const conditions: string[] = [];
   141→  const params: (string | string[])[] = [];
   142→  let paramIndex = 1;
   143→
   144→  if (filter?.search) {
   145→    conditions.push(`r.name ILIKE $${paramIndex}`);
   146→    params.push(`%${filter.search}%`);
   147→    paramIndex++;
   148→  }
   149→
   150→  if (filter?.tags && filter.tags.length > 0) {
   151→    sql += ` JOIN recipe_tags rt ON rt.recipe_id = r.id JOIN tags t ON t.id = rt.tag_id`;
   152→    conditions.push(`t.name = ANY($${paramIndex})`);
   153→    params.push(filter.tags);
   154→    paramIndex++;
   155→  }
   156→
   157→  if (filter?.ingredientIds && filter.ingredientIds.length > 0) {
   158→    sql += ` JOIN recipe_ingredients ri ON ri.recipe_id = r.id`;
   159→    conditions.push(`ri.ingredient_id = ANY($${paramIndex})`);
   160→    params.push(filter.ingredientIds);
   161→    paramIndex++;
   162→  }
   163→
   164→  if (conditions.length > 0) {
   165→    sql += ` WHERE ${conditions.join(" AND ")}`;
   166→  }
   167→
   168→  sql += ` ORDER BY r.created_at DESC`;
   169→
   170→  return query<Recipe>(sql, params);
   171→}
